```c
#include <stdio.h>

int main() {
    int N, i, somme = 0;
    float moyenne;

    printf("Entrer le nombre d'eleves: ");
    scanf("%d", &N);

    int notes[N]; // Déclaration d'un tableau de taille variable (C99)

    // Remplissage du tableau
    for (i = 0; i < N; i++) {
        printf("Note de l'eleve %d (0-20): ", i+1);
        scanf("%d", &notes[i]);
        somme = somme + notes[i];
    }

    // Calcul et affichage de la moyenne
    moyenne = (float)somme / N;
    printf("La moyenne de la classe est: %.2f\n", moyenne);

    return 0;
}
```

